#include <stdio.h>
#include <stdlib.h>
#define MAXN 1000000
int spf[MAXN+1];
void sieve(){
    for(int i=2;i<=MAXN;i++) if(!spf[i]){
        spf[i]=i;
        if((long long)i*i<=MAXN) for(long long j=(long long)i*i;j<=MAXN;j+=i) if(!spf[j]) spf[j]=i;
    }
}
int core(int n){
    int g=0; // gcd of exponents
    int temp=n;
    while(temp>1){
        int p=spf[temp];
        int cnt=0;
        while(temp%p==0){temp/=p;cnt++;}
        g = g? __gcd(g,cnt):cnt;
    }
    // compute minimal base
    int res=1;
    temp=n;
    while(temp>1){
        int p=spf[temp];
        int cnt=0;
        while(temp%p==0){temp/=p;cnt++;}
        int exp = cnt/g;
        for(int i=0;i<exp;i++) res*=p;
    }
    return res;
}
int main(){
    sieve();
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int A,B; scanf("%d %d",&A,&B);
        if(core(A)==core(B)) printf("YES\n"); else printf("NO\n");
    }
    return 0;
}

