import java.io.*;
import java.util.*;
public class Main {
    static final int MAXN = 1_000_000;
    static int[] spf = new int[MAXN+1];
    static void sieve(){
        for(int i=2;i<=MAXN;i++) if(spf[i]==0){
            spf[i]=i;
            if((long)i*i<=MAXN) for(long j=(long)i*i;j<=MAXN;j+=i) if(spf[(int)j]==0) spf[(int)j]=i;
        }
    }
    static int minimalBase(int n){
        int g=0;
        int x=n;
        while(x>1){
            int p=spf[x];
            int cnt=0;
            while(x%p==0){x/=p;cnt++;}
            g = g==0? cnt : gcd(g,cnt);
        }
        int res=1;
        x=n;
        while(x>1){
            int p=spf[x];
            int cnt=0;
            while(x%p==0){x/=p;cnt++;}
            int exp = cnt/g;
            for(int i=0;i<exp;i++) res*=p;
        }
        return res;
    }
    static int gcd(int a,int b){return b==0?a:gcd(b,a%b);}    
    public static void main(String[] args) throws Exception{
        FastScanner fs = new FastScanner(System.in);
        sieve();
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while(T-- > 0){
            int A = fs.nextInt();
            int B = fs.nextInt();
            sb.append(minimalBase(A)==minimalBase(B) ? "YES" : "NO").append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner{
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1<<16];
        private int ptr=0, len=0;
        FastScanner(InputStream is){in=new BufferedInputStream(is);}        
        private int read() throws IOException{ if(ptr>=len){ len=in.read(buffer); ptr=0; if(len==-1) return -1; } return buffer[ptr++]; }
        int nextInt() throws IOException{ int c, sign=1, val=0; do{c=read();}while(c<=32 && c!=-1); if(c=='-'){sign=-1;c=read();} while(c>32 && c!=-1){val=val*10+(c-'0');c=read();} return val*sign; }
    }
}

